async function validateCartStock(cartItems) {
  const productIds = cartItems.map(item => item.id);
  const stocks = await api.getStock(productIds); // { productId: availableStock }
  const invalidItems = [];
  const updatedItems = cartItems.map(item => {
    const available = stocks[item.id];
    if (item.quantity > available) {
      invalidItems.push({ id: item.id, requested: item.quantity, available });
      return { ...item, quantity: available }; // ajuste à la dispo
    }
    return item;
  });
  if (invalidItems.length > 0) {
    useCartStore.getState().setItems(updatedItems);
    toast.warning(`Certains produits ont été ajustés (stock insuffisant)`);
  }
  return { isValid: invalidItems.length === 0, invalidItems };
}
